const checkpoints = [];

// Load data
const productsRaw = JSON.parse(localStorage.getItem('products') || '[]');
const cartRaw = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItemsRaw = JSON.parse(localStorage.getItem('cart_items') || '[]');

const products = Array.isArray(productsRaw) ? productsRaw : [];
const cartItemsAll = Array.isArray(cartItemsRaw) ? cartItemsRaw : [];

// Determine current cart items
let itemsForCart = cartItemsAll;
if (cartRaw && typeof cartRaw === 'object' && cartRaw.id) {
  itemsForCart = cartItemsAll.filter(ci => ci.cart_id === cartRaw.id);
}

// Build product lookup
const productById = {};
products.forEach(p => { productById[p.id] = p; });

// Qualifying products: 10" 5-micron sediment cartridges under $40
const qualifyingProducts = products.filter(p => (
  p && p.status === 'active' &&
  p.category_key === 'cartridge_filters' &&
  p.media_type === 'sediment' &&
  p.length_inch === 10 &&
  p.micron_rating === 5 &&
  typeof p.price === 'number' && p.price < 40
));

if (qualifyingProducts.length === 0 || itemsForCart.length === 0) {
  return 0.0;
}

const qualifyingIds = new Set(qualifyingProducts.map(p => p.id));
const qualifyingCartItems = itemsForCart.filter(ci => qualifyingIds.has(ci.product_id));

// Determine cheapest qualifying product(s)
const cheapestPrice = Math.min.apply(null, qualifyingProducts.map(p => p.price));
const cheapestProducts = qualifyingProducts.filter(p => p.price === cheapestPrice);
const cheapestIds = new Set(cheapestProducts.map(p => p.id));
const cheapestCartItems = qualifyingCartItems.filter(ci => cheapestIds.has(ci.product_id));

// CP1 (0.30): Cart contains at least one qualifying 10" 5µm sediment cartridge under $40
checkpoints.push({
  passed: qualifyingCartItems.length > 0,
  weight: 0.30
});

// CP2 (0.30): Cart contains the cheapest qualifying cartridge model
checkpoints.push({
  passed: cheapestCartItems.length > 0,
  weight: 0.30
});

// CP3 (0.40): Quantity of the cheapest qualifying cartridge is at least 2 units
const hasTwoOrMoreCheapest = cheapestCartItems.some(ci => (ci.quantity || 0) >= 2);
checkpoints.push({
  passed: hasTwoOrMoreCheapest,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

