const sedimentProducts = products.filter(p => (
  p && p.status === 'active' &&
  p.category_key === 'cartridge_filters' &&
  p.media_type === 'sediment' &&
  p.length_inch === 10 &&
  typeof p.price === 'number' && p.price <= 60 &&
  (p.rating || 0) >= 4
));

