  p && p.status === 'active' &&
  p.category_key === 'cartridge_filters' &&
  p.media_type === 'carbon_block' &&
  p.length_inch === 10 &&
  typeof p.price === 'number' && p.price <= 60 &&
  (p.rating || 0) >= 4
));

