  p && p.status === 'active' &&
  p.category_key === 'cartridge_filters' &&
  p.media_type === 'polishing' &&
  p.length_inch === 10 &&
  p.micron_rating === 1 &&
  typeof p.price === 'number' && p.price <= 60 &&
