  return 0.0;
}

const sedCheapest = getCheapest(sedimentProducts);
const carbCheapest = getCheapest(carbonProducts);
const polCheapest = getCheapest(polishingProducts);

const sedIds = new Set(sedimentProducts.map(p => p.id));
const carbIds = new Set(carbonProducts.map(p => p.id));
const polIds = new Set(polishingProducts.map(p => p.id));

