const checkpoints = [];

// Load data
const productsRaw = JSON.parse(localStorage.getItem('products') || '[]');
const cartRaw = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItemsRaw = JSON.parse(localStorage.getItem('cart_items') || '[]');
const comparisonListsRaw = JSON.parse(localStorage.getItem('comparison_lists') || '[]');
const comparisonItemsRaw = JSON.parse(localStorage.getItem('comparison_items') || '[]');

const products = Array.isArray(productsRaw) ? productsRaw : [];
const cartItemsAll = Array.isArray(cartItemsRaw) ? cartItemsRaw : [];
const comparisonLists = Array.isArray(comparisonListsRaw) ? comparisonListsRaw : [];
const comparisonItems = Array.isArray(comparisonItemsRaw) ? comparisonItemsRaw : [];

if (!comparisonLists.length) {
  return 0.0;
}

// Use the current (first) comparison list
const list = comparisonLists[0];
const itemsInList = comparisonItems.filter(it => it.comparison_list_id === list.id);

// Product lookup
const productById = {};
products.forEach(p => { productById[p.id] = p; });

const comparedProducts = itemsInList
  .map(it => productById[it.product_id])
  .filter(p => !!p);

// Qualifying compared conductivity meters
const qualifyingCompared = comparedProducts.filter(p => (
  p && p.status === 'active' &&
  p.category_key === 'instrumentation' &&
  p.instrument_type === 'conductivity_meter' &&
  typeof p.price === 'number' && p.price <= 500 &&
  (p.rating || 0) >= 4
));

if (!qualifyingCompared.length) {
  return 0.0;
}

// Determine metric: max_conductivity if present, else measurement_range_max
function conductivityMetric(p) {
  if (typeof p.max_conductivity === 'number') return p.max_conductivity;
  if (typeof p.measurement_range_max === 'number') return p.measurement_range_max;
  return 0;
}

let maxValue = -Infinity;
qualifyingCompared.forEach(p => {
  const m = conductivityMetric(p);
  if (m > maxValue) maxValue = m;
});

if (maxValue === -Infinity) {
  return 0.0;
}

const highestProducts = qualifyingCompared.filter(p => conductivityMetric(p) === maxValue);
const highestIds = new Set(highestProducts.map(p => p.id));

// Current cart items
let itemsForCart = cartItemsAll;
if (cartRaw && typeof cartRaw === 'object' && cartRaw.id) {
  itemsForCart = cartItemsAll.filter(ci => ci.cart_id === cartRaw.id);
}

const highestCartItems = itemsForCart.filter(ci => highestIds.has(ci.product_id));

// CP1 (0.40): At least three qualifying conductivity meters were added to comparison
checkpoints.push({
  passed: qualifyingCompared.length >= 3,
  weight: 0.40
});

// CP2 (0.60): Cart contains a meter that is among the compared meters with the highest maximum conductivity range
checkpoints.push({
  passed: highestCartItems.length > 0,
  weight: 0.60
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

